{
  "prompt": "Studio portrait of a young adult woman with long wavy red hair and fair freckled skin, wearing a black sequined strapless mini dress and thigh-high black boots. She is seated on the floor in a relaxed yet confident pose, facing forward with a soft, neutral expression. A black ribbon choker drapes loosely around her neck. The scene is lit with warm, golden studio lighting that creates a circular spotlight effect behind her, casting soft shadows and adding depth. Minimalist background, editorial fashion photography style, high detail, cinematic warmth, smooth gradients.",
  "negative_prompt": "lowres, blurry, bad anatomy, extra limbs, deformed hands, distorted face, harsh shadows, overexposed, underexposed, watermark, text, logo, jpeg artifacts, cartoon, CGI, 3D render",
  "style": "editorial fashion photography, photorealistic",
  "camera": {
    "angle": "eye-level",
    "framing": "three-quarter body portrait",
    "lens": "85mm",
    "aperture": "f/2.0"
  },
  "lighting": {
    "type": "studio lighting",
    "setup": "warm spotlight with soft falloff",
    "mood": "cinematic and intimate"
  },
  "setting": {
    "location": "studio",
    "background": "warm gradient backdrop with circular light vignette"
  },
  "color_palette": [
    "black",
    "warm gold",
    "amber",
    "soft beige"
  ],
  "size": "768x1152"
}

{
  "type": "collection of instant photos",
  "setting": "laid out flat on a white fabric surface",
  "character": {
    "hair": "{argument name=\"hair color\" default=\"long pink hair with blue inner color\"}",
    "outfit": "{argument name=\"outfit\" default=\"black and white maid uniform with frilly headband and black ribbons\"}",
    "eyes": "reddish-pink"
  },
  "layout": {
    "arrangement": "two rows of five polaroid photos",
    "count": 10,
    "photos": [
      { "position": "top row 1", "description": "holding a pink heart cushion" },
      { "position": "top row 2", "description": "winking, making a peace sign" },
      { "position": "top row 3", "description": "making a hand heart, pink heart doodle on the bottom border" },
      { "position": "top row 4", "description": "resting chin on hands, gentle smile" },
      { "position": "top row 5", "description": "holding a red rose, winking" },
      { "position": "bottom row 1", "description": "finger to lips, shy expression" },
      { "position": "bottom row 2", "description": "holding a small pink cake" },
      { "position": "bottom row 3", "description": "winking, hand near face, signature '{argument name=\"signature text\" default=\"Hanashi\"}' and heart doodle on border" },
      { "position": "bottom row 4", "description": "holding a pink bunny plushie, sparkle doodles, signature '{argument name=\"signature text\" default=\"Hanashi\"}' and bunny doodle on border" },
      { "position": "bottom row 5", "description": "winking, sparkle doodles, message '{argument name=\"message text\" default=\"いつも応援ありがとう！これからもよろしくね♪\"}' and signature '{argument name=\"signature text\" default=\"Hanashi\"}' on border" }
    ]
  }
}

{
  "type": "2x2 portrait grid",
  "subject": "{argument name=\"subject description\" default=\"young adult East Asian male with short black hair and a slight smile\"}",
  "style": "photorealistic, high-resolution, professional lighting, consistent facial identity across all panels",
  "layout": {
    "format": "2x2 grid",
    "panel_count": 4,
    "panels": [
      {
        "position": "top-left",
        "description": "{argument name=\"profession 1\" default=\"Corporate professional wearing a dark navy suit, white shirt, and blue tie against a gray textured background\"}"
      },
      {
        "position": "top-right",
        "description": "{argument name=\"profession 2\" default=\"Casual attire wearing a dark blue crew neck t-shirt against a blurred outdoor park background\"}"
      },
      {
        "position": "bottom-left",
        "description": "{argument name=\"profession 3\" default=\"Construction worker wearing a yellow hard hat, navy blue work shirt, and bright orange high-visibility vest against a blurred warehouse background\"}"
      },
      {
        "position": "bottom-right",
        "description": "{argument name=\"profession 4\" default=\"Medical professional wearing a white lab coat over a light blue collared shirt against a blurred laboratory background\"}"
      }
    ]
  }
}

{
  "type": "character avatar grid",
  "theme": "{argument name=\"theme\" default=\"Journey to the West mythology\"}",
  "style": "{argument name=\"art style\" default=\"clean 2D cartoon vector illustration, thick outlines, flat colors\"}",
  "layout": {
    "background": "{argument name=\"background color\" default=\"light gray\"} subtle texture",
    "format": "grid of circular portraits with text labels centered below each circle",
    "rows": [
      {
        "count": 4,
        "items": [
          {"label": "Sun Wukong", "description": "monkey boy with golden headband and red scarf"},
          {"label": "Tang Sanzang", "description": "monk with ornate golden crown"},
          {"label": "Zhu Bajie", "description": "pig man holding a rake"},
          {"label": "Sha Wujing", "description": "bearded man holding a crescent moon staff"}
        ]
      },
      {
        "count": 4,
        "items": [
          {"label": "White Dragon Horse", "description": "white horse with golden bridle"},
          {"label": "Jade Emperor", "description": "older man with white beard and golden crown"},
          {"label": "Guanyin", "description": "goddess holding a willow branch"},
          {"label": "Bull Demon Kink", "description": "fierce bull demon in armor"}
        ]
      },
      {
        "count": 4,
        "items": [
          {"label": "Princess Iron Fan", "description": "woman holding a green palm leaf fan"},
          {"label": "Red Boy", "description": "boy with red hair, horns, and a small flame"},
          {"label": "Black Wind Demon", "description": "dark shadowy demon with glowing red eyes"},
          {"label": "Nezha", "description": "boy with double hair buns holding a flaming spear"}
        ]
      },
      {
        "count": 3,
        "description": "partial row repeating Princess Iron Fan, Black Wind Demon, and Nezha, slightly cropped at the bottom"
      }
    ]
  }
}

{
  "type": "logo design concept sheet",
  "style": "{argument name=\"overall style\" default=\"anime VTuber typography, highly decorative, gradient text\"}",
  "background": "solid white",
  "layout": {
    "arrangement": "2 rows by 3 columns",
    "count": 6
  },
  "logos": [
    {
      "main_text": "{argument name=\"logo 1 text\" default=\"火乃神ルカ\"}",
      "sub_text": "Hinokami Luka",
      "theme": "{argument name=\"logo 1 theme\" default=\"fire, shrine gate, bell, intense red and gold\"}"
    },
    {
      "main_text": "{argument name=\"logo 2 text\" default=\"星名ミラ\"}",
      "sub_text": "Hoshina Mira",
      "theme": "{argument name=\"logo 2 theme\" default=\"space, stars, rocket, shooting star, blue and purple gradient\"}"
    },
    {
      "main_text": "常盤ネム",
      "sub_text": "Tokiwa Nemu",
      "theme": "sleep, night sky, clouds, crescent moon, Zzz, soft pastel blue and purple"
    },
    {
      "main_text": "白藤こよみ",
      "sub_text": "Shirafuji Koyomi",
      "theme": "four seasons, wisteria, cherry blossoms, autumn leaves, soft pastel colors"
    },
    {
      "main_text": "天音しずく",
      "sub_text": "Amane Shizuku",
      "theme": "water, rain drops, crescent moon, clear blue colors"
    },
    {
      "main_text": "月城レイナ",
      "sub_text": "Tsukishiro Reina",
      "theme": "night, castle silhouette, large crescent moon, stars, dark purple galaxy colors"
    }
  ]
}

{
  "type": "character avatar icon set",
  "theme": "{argument name=\"theme\" default=\"Journey to the West characters\"}",
  "style": "{argument name=\"art style\" default=\"clean flat vector illustration, cartoon style, solid colors, thick outlines\"}",
  "background": "{argument name=\"background\" default=\"light gray textured background\"}",
  "layout": {
    "description": "2 rows of 4 circular portraits, each with Chinese and English text labels underneath",
    "center_text": "{argument name=\"watermark\" default=\"@austinit\"}"
  },
  "avatars": [
    {
      "chinese_label": "孙悟空",
      "english_label": "Sun Wukong",
      "visuals": "monkey with golden headband, yellow shirt, blue scarf, holding a golden cudgel"
    },
    {
      "chinese_label": "唐僧",
      "english_label": "Tang Sanzang",
      "visuals": "serene monk in red and gold robes, ornate five-lobed crown, holding a monk's staff"
    },
    {
      "chinese_label": "猪八戒",
      "english_label": "Zhu Bajie",
      "visuals": "smiling pig-man in black robe, holding a nine-tooth rake"
    },
    {
      "chinese_label": "沙悟净",
      "english_label": "Sha Wujing",
      "visuals": "bearded man with crescent headband, green robe, large beaded necklace, holding a crescent-moon spade"
    },
    {
      "chinese_label": "白龙马",
      "english_label": "White Dragon Horse",
      "visuals": "white horse head with a decorative bridle"
    },
    {
      "chinese_label": "太上老君",
      "english_label": "Taishang Laojun",
      "visuals": "elderly sage with long white beard, yellow robe, golden halo behind head, hand raised in a teaching gesture"
    },
    {
      "chinese_label": "观音菩萨",
      "english_label": "Guanyin",
      "visuals": "serene goddess in white hooded robes, ornate jewelry, hand raised in blessing"
    },
    {
      "chinese_label": "牛魔王",
      "english_label": "Bull Demon King",
      "visuals": "fierce blue-skinned minotaur with black horns, red hair, wearing armor and a red scarf"
    }
  ]
}
